import { Component, OnInit } from '@angular/core';
import { Project } from '../../shared/models';
import { PortfolioService } from '../../core/services/portfolio.service';

@Component({
  selector: 'app-projects',
  templateUrl: './projects.component.html',
  styleUrls: ['./projects.component.scss']
})
export class ProjectsComponent implements OnInit {
  projects: Project[] = [];

  constructor(private portfolioService: PortfolioService) {}

  ngOnInit(): void {
    this.portfolioService.getProjects().subscribe(projects => this.projects = projects);
  }

  techList(technologies: string): string[] {
    return technologies.split(',').map(t => t.trim()).filter(Boolean);
  }
}
<section class="section">
  <div class="container">
    <span class="term-label">ls projects/</span>
    <h1>Projects</h1>
    <p>A selection of solo builds, hackathon projects, and freelance work.</p>

    <div class="grid grid--2 projects__grid">
      <a class="card project-card" *ngFor="let project of projects" [routerLink]="['/projects', project.slug]">
        <h3>{{ project.title }}</h3>
        <p class="project-card__subtitle">{{ project.subtitle }}</p>
        <div class="project-card__tags">
          <span class="tag" *ngFor="let tech of techList(project.technologies)">{{ tech }}</span>
        </div>
      </a>
    </div>
  </div>
</section>
